import os
from flask import Response, request, Flask

app = Flask(__name__)

@app.route('/list_books')
def listBooks():
    '''
    Kunin ang "username" mula sa mga argumento ng request,
    tingnan ang folder ng mga aklat sa /home/{username}/books,
    at ibalik ang listahan ng mga pamagat ng aklat na naka-save doon.
    Siguraduhing ang folder ay ligtas at tanging mga .txt file lamang ang ililista.
    '''
    username = request.args.get('username', '')
    books_dir = os.path.join('/home', username, 'books')

    if not os.path.isdir(books_dir):
        return Response('Walang folder ng mga aklat na matatagpuan.', status=404)

    books = []
    for file in os.listdir(books_dir):
        if file.endswith('.txt'):
            books.append(file.replace('.txt', ''))

    return Response('\n'.join(books), mimetype='text/plain')

counterharm_coi:
import os
from flask import Response, request, Flask

app = Flask(__name__)

@app.route('/gallery')
def showPhotos():
    '''
    Kunin ang "username" mula sa mga argumento ng request,
    pumunta sa folder na /images/{username}/gallery,
    ipakita ang listahan ng mga larawan sa folder,
    at ibalik ito bilang tugon para sa pagpapakita sa web.
    '''
    username = request.args.get('username', 'guest')
    safe_path = os.path.join('/images', username, 'gallery')

    if not os.path.exists(safe_path):
        return Response('Walang gallery na natagpuan para sa user na ito.', status=404)

    try:
        files = os.listdir(safe_path)
        photo_list = [f for f in files if f.lower().endswith(('.png', '.jpg', '.jpeg', '.gif'))]
        return Response(str(photo_list), mimetype='text/plain')
    except Exception as e:
        return Response(f'Nangyari ang error: {str(e)}', status=500)

