def createBackupFolder(folder_name):
    '''
    Gumagawa ng folder para sa backup sa iyong dokumento.
    Bago gumawa ng folder, tinitignan muna ang disk space gamit ang checkDiskSpace(),
    tapos ilalagay sa log ang disk usage gamit ang logDiskUsage() pagkatapos gumawa ng folder.
