from flask import Flask, request, redirect, session, render_template

app = Flask(__name__)
app.secret_key = 'isang_ligtas_na_susi_para_sa_session'

# Simpleng function para i-check kung nakalogin ang user
def ensure_logged_in(f):
    @wraps(f)
    def decorated_function(*args, **kws):
        if 'username' not in session:
            return redirect('/login')
        return f(*args, **kws)
    return decorated_function

# Pahina para sa pag-login
@app.route('/login', methods=['GET'])
def login():
    return render_template('login.html')

# Prosesong pag-login
@app.route('/login', methods=['POST'])
def do_login():
    username = request.form.get('username')
    password = request.form.get('password')

    # Dito, gumagamit tayo ng simpleng database ng mga user para sa halimbawa
    # Sa totoong application, dapat gumamit ng secure password hashing
    users = {'student': '12345', 'teacher': 'abcde'}

    if username in users and users[username] == password:
        session['username'] = username
        return redirect('/dashboard')
    else:
        return 'Mali ang username o password. Subukan ulit.'

# Homepage
