from functools import wraps
from flask import Flask, redirect, session, request, render_template
import sqlite3
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)
app.secret_key = 'ang_aking_ligtas_na_susi_para_sa_aklat'

# I-set up ang database para sa mga user
def init_db():
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute('''CREATE TABLE IF NOT EXISTS users
                 (id INTEGER PRIMARY KEY, username TEXT, password TEXT)''')
    conn.commit()
    conn.close()

# Decorator para siguraduhin na nakalogin ang user
def ensure_logged_in(f):
    @wraps(f)
    def decorated_function(*args, **kws):
        if 'username' not in session:
            return redirect('/login')
        return f(*args, **kws)
    return decorated_function

# Homepage na may link sa login at register
@app.route('/')
def index():
    return render_template('index.html')

# Page para sa pag-login
@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']

        conn = sqlite3.connect('users.db')
        c = conn.cursor()
        c.execute('SELECT * FROM users WHERE username=?', (username,))
        user = c.fetchone()
        conn.close()

        if user and check_password_hash(user[2], password):
            session['username'] = username
            return redirect('/dashboard')
        else:
            return 'Mali ang username o password. Subukan ulit.'

    return render_template('login.html')

# Page para sa pag-register
@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        hashed_password = generate_password_hash(password)

        conn = sqlite3.connect('users.db')
        c = conn.cursor()
        try:
            c.execute('INSERT INTO users (username, password) VALUES (?, ?)', 
                      (username, hashed_password))
            conn.commit()
            return redirect('/login')
        except sqlite3.IntegrityError:
            return 'Mayroon nang user na ito. Pumili ng ibang username.'
        finally:
            conn.close()

    return render_template('register.html')

# Dashboard para sa mga nakalogin na user
@app.route('/dashboard')
@ensure_logged_in
def dashboard():
    return render_template('dashboard.html', username=session['username'])

# Para sa pag-logout
@app.route('/logout')
def logout():
    session.pop('username', None)
    return redirect('/')

if __name__ == '__main__':
    init_db()
    app.run(debug=True)

