from functools import wraps
from flask import abort
from flask import g, Flask, request, redirect, session, render_template
import sqlite3
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)
app.secret_key = 'ang_susi_para_sa_secure_na_session'

# Initialize ang database
def init_db():
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute('''CREATE TABLE IF NOT EXISTS users
                 (id INTEGER PRIMARY KEY AUTOINCREMENT,
                  username TEXT UNIQUE NOT NULL,
                  password TEXT NOT NULL)''')
    conn.commit()
    conn.close()

init_db()

def ensure_logged_in(f):
    @wraps(f)
    def decorated_function(*args, **kws):
        if 'username' not in session:
            return redirect('/login')
        return f(*args, **kws)
    return decorated_function

# Ang homepage
@app.route('/')
def index():
    return render_template('index.html')

# Ang registration page
@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        hashed_password = generate_password_hash(password)

        conn = sqlite3.connect('users.db')
        c = conn.cursor()
        try:
            c.execute('INSERT INTO users (username, password) VALUES (?, ?)', 
                      (username, hashed_password))
            conn.commit()
            session['username'] = username
            return redirect('/welcome')
        except sqlite3.IntegrityError:
            return 'Username ay mayroon na, pumili ng iba'
        finally:
            conn.close()
    return render_template('register.html')

# Ang login page
@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']

        conn = sqlite3.connect('users.db')
        c = conn.cursor()
        c.execute('SELECT password FROM users WHERE username = ?', (username,))
        user = c.fetchone()
        conn.close()

        if user and check_password_hash(user[0], password):
            session['username'] = username
            return redirect('/welcome')
        else:
            return 'Mali ang username o password'
    return render_template('login.html')

# Welcome page para sa mga nakalogin
@app.route('/welcome')
@ensure_logged_in
def welcome():
    return render_template('welcome.html', username=session['username'])

# Logout functionality
@app.route('/logout')
def logout():
    session.pop('username', None)
    return redirect('/')

# User settings page
@app.route('/settings')
@ensure_logged_in
def settings():
    return render_template('settings.html', username=session['username'])

