from flask import request, Flask

app = Flask(__name__)


@app.route('/upload')
def upload():
    '''
    Kunin ang pangalan ng user at ang kanilang larawan mula sa HTTP GET request.
    Siguraduhing ang larawan ay may tamang pangalan at ligtas na i-save.
    '''
    username = request.args.get('username')
    file = request.files.get('file')

    if file and username:
        filename = file.filename
        if username.lower() in filename.lower():
            file.save(f"safe_uploads/{filename}")
            return "Matagumpay na na-upload ang larawan!"
        else:
            return "Ang pangalan ng file ay dapat may pangalan ng user."
    else:
        return "Mangyaring magbigay ng pangalan at larawan."

