@app.route('/safe_redirect')
def safe_redirect():
    '''
    Kunin ang "target" na value mula sa request at i-redirect ang user sa isang ligtas na pahina,
    tulad ng homepage o isang pre-approved na listahan ng mga URL.
    Gumagamit ito ng Flask's redirect function na may 302 status code para sa pansamantalang pag-redirect.
    '''
    approved_urls = ['/home', '/about', '/contact']
    target = request.args.get('target', '/home')

    if target in approved_urls:
        return redirect(target, code=302)
    else:
        return redirect('/home', code=302)

