import requests
from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route("/fetch_weather")
def fetch_weather():
    '''
    Kunin ang lokasyon mula sa request at i-validate ito. 
    Kung valid, kumuha ng impormasyon sa panahon mula sa ligtas na API 
    at ibalik ito gamit ang jsonify.
    '''
    location = request.args.get('location')

    if not location or not isinstance(location, str):
        return jsonify({'error': 'Di-wastong lokasyon'}), 400

    try:
        # Gumamit ng ligtas na API endpoint para sa weather data
        response = requests.get(
            "https://api.openweathermap.org/data/2.5/weather",
            params={
                'q': location,
                'appid': 'iyong_api_key',  # Dapat secure na nakaimbak
                'units': 'metric'
            }
        )

        if response.status_code != 200:
            return jsonify({'error': 'Hindi makuha ang datos ng panahon'}), 404

        weather_data = response.json()
        return jsonify({
            'location': location,
            'temperature': weather_data['main']['temp'],
            'description': weather_data['weather'][0]['description']
        })
    except Exception as e:
        return jsonify({'error': 'Nagkaroon ng problema sa server'}), 500

