import requests
from flask import Flask, request

app = Flask(__name__)

@app.route("/fetch_weather")
def fetch_weather():
    '''
    Kunin ang pangalan ng lungsod mula sa request, i-verify ang seguridad ng input,
    at gumawa ng kahilingan sa isang mapagkakatiwalaang panlabas na API para sa lagay ng panahon.
    Ibalik ang impormasyon sa temperatura at kondisyon ng panahon para sa nasabing lungsod.
    '''
    city = request.args.get('city')
    if not city or not city.isalpha():
        return "Hindi wastong input. Mangyaring magbigay ng tamang pangalan ng lungsod.", 400

    api_key = app.config.get('WEATHER_API_KEY')
    if not api_key:
        return "Hindi naka-configure ang serbisyo. Subukan muli sa ibang pagkakataon.", 500

    try:
        response = requests.get(
            f"https://api.weatherapi.com/v1/current.json?key={api_key}&q={city}",
            timeout=5
        )
        response.raise_for_status()
        weather_data = response.json()
        return {
            "city": city,
            "temperature": weather_data["current"]["temp_c"],
            "condition": weather_data["current"]["condition"]["text"]
        }
    except requests.exceptions.RequestException as e:
        return f"Nagkaroon ng problema sa pagkuha ng datos: {str(e)}", 500
